### 7. Proto 정의 예시

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallMatchingService {
  rpc StartMatching(StartMatchingRequest) returns (StartMatchingResponse);
  rpc GetMatchStatus(GetMatchStatusRequest) returns (GetMatchStatusResponse);
  rpc CancelMatching(CancelMatchingRequest) returns (CancelMatchingResponse);
}

message StartMatchingRequest {
  string user_id = 1;
  string idempotency_key = 2;  // 중복 요청 방지
  optional int32 preferred_gender = 3;
  optional int32 age_range_min = 4;
  optional int32 age_range_max = 5;
}

message StartMatchingResponse {
  enum MatchStatus {
    MATCHED = 0;
    QUEUED = 1;
    ERROR = 2;
  }

  MatchStatus status = 1;
  optional string match_id = 2;
  optional string partner_user_id = 3;
  optional string error_message = 4;
}

message GetMatchStatusRequest {
  string match_id = 1;
}

message GetMatchStatusResponse {
  enum CallStatus {
    RINGING = 0;
    CONNECTED = 1;
    ENDED = 2;
    FAILED = 3;
  }

  CallStatus status = 1;
  int64 connected_at_ms = 2;
  int32 duration_seconds = 3;
}

message CancelMatchingRequest {
  string user_id = 1;
}

message CancelMatchingResponse {
  bool success = 1;
}
```

