### 8. GraphQL 스키마 정의 예시

```graphql
type CallMatch {
  id: ID!
  partnerId: String!
  status: CallMatchStatus!
  connectedAt: String
  durationSeconds: Int
  createdAt: String!
}

enum CallMatchStatus {
  MATCHED
  RINGING
  CONNECTED
  ENDED
  FAILED
}

type MatchingQueueStatus {
  isQueued: Boolean!
  position: Int
  estimatedWaitSeconds: Int
  queueSize: Int!
}

extend type Query {
  matchingStatus: MatchingQueueStatus
  callMatch(matchId: ID!): CallMatch
}

extend type Mutation {
  startCallMatching(
