#### 6.1 동시성 테스트
```kotlin
@ExtendWith(MockitoExtension::class)
class CallMatchingServiceConcurrencyTest {

    @Mock
    private lateinit var callQueueRepository: CallQueueRepository

    @Mock
    private lateinit var callMatchRepository: CallMatchRepository

    @InjectMocks
    private lateinit var callMatchingService: CallMatchingService

    @Test
    fun `should prevent duplicate matching under concurrent requests`() {
        // given
        val user1 = "user-1"
        val user2 = "user-2"
        val executor = Executors.newFixedThreadPool(2)
        val latch = CountDownLatch(2)
        val results = Collections.synchronizedList<MatchResult>(mutableListOf())

        // when: 두 사용자가 동시에 매칭 요청
        executor.submit {
            try {
                val result = callMatchingService.startMatching(user1)
                results.add(result)
            } finally {
                latch.countDown()
            }
        }

        executor.submit {
            try {
                val result = callMatchingService.startMatching(user2)
                results.add(result)
            } finally {
                latch.countDown()
            }
        }

        latch.await(5, TimeUnit.SECONDS)

        // then: 정확히 하나만 매칭되어야 함
        assertThat(results).hasSize(2)
        assertThat(results.count { it.status == MatchStatus.MATCHED })
            .isEqualTo(1)
    }
